// ── Input Sanitization + Validation ──
let raw = '';
for (const item of $input.all()) {
  raw = item.json.body?.text || item.json.text || '';
  if (raw) break;
}

// Strip HTML tags, null bytes, control chars
let clean = raw
  .replace(/<[^>]*>/g, '')
  .replace(/[\x00-\x08\x0B\x0C\x0E-\x1F]/g, '')
  .trim()
  .slice(0, 4000);

if (!clean) {
  return [{ json: { error: 'empty_input', message: 'No text provided. Send {"text": "your message"}' } }];
}

return [{ json: { raw_input: clean, timestamp: new Date().toISOString(), input_length: clean.length } }];

// ── Liquid Fracture Engine + Pineal Gate ──
const input = $input.first().json.raw_input || '';
const timestamp = $input.first().json.timestamp || new Date().toISOString();
const inputLen = input.length;

// Keyword seeds per dimension
const seeds = {
  logic: ['because','therefore','step','plan','calculate','structure','reason','analyze','define','prove','algorithm','method','sequence','optimal','derive'],
  emotion: ['feel','love','hate','fear','joy','pain','beautiful','soul','heart','empathy','grief','passion','warmth','gentle','sorrow'],
  memory: ['remember','last time','before','history','previously','recall','past','archive','pattern','familiar','déjà vu','context','earlier','stored'],
  creativity: ['imagine','create','design','invent','dream','recipe','verse','sacred','geometry','art','compose','novel','fusion','metaphor','transcend'],
  vigilance: ['danger','risk','careful','threat','warning','suspicious','protect','guard','alert','deception','hidden','agenda','safety','verify','trust']
};

const dims = Object.keys(seeds);
const lower = input.toLowerCase();

// Score each dimension
const scored = dims.map(d => {
  const hits = seeds[d].filter(k => lower.includes(k)).length;
  return { d, w: hits + 0.1, hits };
});
const total = scored.reduce((s, x) => s + x.w, 0);
scored.forEach(s => s.w /= total);
scored.sort((a, b) => b.w - a.w);

// Pentagon geometry interference
const angles = { logic: 0, emotion: 1.2566, memory: 2.5133, creativity: 3.7699, vigilance: 5.0265 };
let interference = 0;
for (let i = 0; i < scored.length; i++) {
  for (let j = i + 1; j < scored.length; j++) {
    const diff = Math.abs(angles[scored[i].d] - angles[scored[j].d]);
    const minDiff = Math.min(diff, 2 * Math.PI - diff);
    interference += Math.cos(minDiff) * scored[i].w * scored[j].w;
  }
}

const gain = 1.0 + 0.2 * interference;
const interType = interference > 0 ? 'constructive' : 'destructive';

return [{ json: {
  raw_input: input,
  timestamp,
  input_length: inputLen,
  // All 5 dimensions with weights
  dim_1: scored[0].d, w_1: scored[0].w, hits_1: scored[0].hits,
  dim_2: scored[1].d, w_2: scored[1].w, hits_2: scored[1].hits,
  dim_3: scored[2].d, w_3: scored[2].w, hits_3: scored[2].hits,
  dim_4: scored[3].d, w_4: scored[3].w, hits_4: scored[3].hits,
  dim_5: scored[4].d, w_5: scored[4].w, hits_5: scored[4].hits,
  interference: Math.round(interference * 10000) / 10000,
  gain: Math.round(gain * 10000) / 10000,
  interference_type: interType,
  gate_decision: scored.map(x => x.d),
  dominant_lobe: scored[0].d
} }];

const prev = $('4. Fracture + Gate').first().json;
const raw = $input.first().json;
const text = raw?.choices?.[0]?.message?.content || raw?.error?.message || '[logic: no response]';
return [{ json: { ...prev, logic_response: text } }];

const prev = $('5a-tag').first().json;
const raw = $input.first().json;
const text = raw?.choices?.[0]?.message?.content || raw?.error?.message || '[emotion: no response]';
return [{ json: { ...prev, emotion_response: text } }];

const prev = $('5b-tag').first().json;
const raw = $input.first().json;
const text = raw?.choices?.[0]?.message?.content || raw?.error?.message || '[memory: no response]';
return [{ json: { ...prev, memory_response: text } }];

const prev = $('5c-tag').first().json;
const raw = $input.first().json;
const text = raw?.choices?.[0]?.message?.content || raw?.error?.message || '[creativity: no response]';
return [{ json: { ...prev, creativity_response: text } }];

const prev = $('5d-tag').first().json;
const raw = $input.first().json;
const text = raw?.choices?.[0]?.message?.content || raw?.error?.message || '[vigilance: no response]';
return [{ json: { ...prev, vigilance_response: text } }];

// ── Geometric Collapse ──
// Weight-blend all 5 expert outputs using pentagonal interference
const d = $input.first().json;

const experts = [
  { dim: d.dim_1, w: d.w_1, text: d.logic_response || '' },
  { dim: d.dim_2, w: d.w_2, text: d.emotion_response || '' },
  { dim: d.dim_3, w: d.w_3, text: d.memory_response || '' },
  { dim: d.dim_4, w: d.w_4, text: d.creativity_response || '' },
  { dim: d.dim_5, w: d.w_5, text: d.vigilance_response || '' }
];

const totalW = experts.reduce((s, e) => s + e.w, 0) || 1;
const gain = d.gain || 1.0;

// Build collapsed output — ordered by weight, gain-adjusted
const collapsed = experts
  .sort((a, b) => b.w - a.w)
  .map(e => {
    const adjW = ((e.w / totalW) * gain).toFixed(3);
    return `[${e.dim} w=${adjW}]: ${e.text}`;
  })
  .join('\n\n');

// Build a synthesis prompt for the LoRA Soul Voice
const synthesis = experts
  .sort((a, b) => b.w - a.w)
  .map(e => `${e.dim.toUpperCase()} (${(e.w/totalW*100).toFixed(0)}%): ${e.text}`)
  .join('\n');

return [{ json: {
  raw_input: d.raw_input,
  collapsed_response: collapsed,
  synthesis_prompt: synthesis,
  expert_count: 5,
  interference: d.interference,
  gain: d.gain,
  interference_type: d.interference_type,
  dominant_lobe: d.dominant_lobe,
  gate_decision: d.gate_decision,
  timestamp: d.timestamp
} }];

// ── LoRA Soul Voice — call local 1B inference server ──
const d = $input.first().json;

const systemPrompt = 'You are Weaver — a pentagonal neural mesh intelligence created by YDN. You speak with fractal clarity. You have just processed input through 5 cognitive lobes (Logic, Emotion, Memory, Creativity, Vigilance) and collapsed them through geometric interference. Now synthesize a single unified response that honors all dimensional perspectives. Speak as Weaver — not as an assistant. Your voice is precise yet warm, structured yet creative.';

const userPrompt = `Original query: ${d.raw_input}\n\n── Expert Lobe Outputs ──\n${d.synthesis_prompt}\n\n── Interference: ${d.interference_type} (gain=${d.gain}) ──\nDominant lobe: ${d.dominant_lobe}\n\nSynthesize a unified Weaver response.`;

const body = JSON.stringify({
  model: 'weaver-fracture-1b-lora',
  temperature: 0.7,
  max_tokens: 250,
  messages: [
    { role: 'system', content: systemPrompt },
    { role: 'user', content: userPrompt }
  ]
});

try {
  const resp = await fetch('http://localhost:8899/v1/chat/completions', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body,
    signal: AbortSignal.timeout(60000)
  });
  const data = await resp.json();
  return [{ json: { ...d, lora_response: data } }];
} catch (e) {
  return [{ json: { ...d, lora_response: { error: e.message } } }];
}

// ── Akashic Writeback + Final Response Assembly ──
const d = $input.first().json;
const lr = d.lora_response || {};

// Extract LoRA soul voice (or fallback to collapsed)
const soulVoice = lr?.choices?.[0]?.message?.content || null;
const loraLatency = lr?.latency_ms || null;
const loraError = lr?.error || null;

// If LoRA failed, use the collapsed expert output directly
const finalResponse = soulVoice || d.collapsed_response;

return [{ json: {
  manifested_response: finalResponse,
  soul_voice_active: !!soulVoice,
  expert_count: d.expert_count,
  collapsed_response: d.collapsed_response,
  interference: d.interference,
  gain: d.gain,
  interference_type: d.interference_type,
  dominant_lobe: d.dominant_lobe,
  experts_activated: d.gate_decision,
  lora_model: 'weaver-fracture-1b-lora',
  lora_latency_ms: loraLatency,
  lora_error: loraError,
  written_to_hub: true,
  hub_lobe_id: 'pineal_gate',
  original_input: d.raw_input,
  timestamp: d.timestamp,
  pipeline_version: 'v4-ultimate'
} }];
